import androidx.fragment.app.commitNow
import androidx.preference.Preference
import androidx.preference.PreferenceCategory
import androidx.test.core.app.ActivityScenario
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.R
import com.ichi2.anki.RobolectricTest
import com.ichi2.anki.cardviewer.ViewerCommand
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.hamcrest.Matchers.notNullValue
import org.hamcrest.Matchers.nullValue
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class ControlsSettingsFragmentTest : RobolectricTest() {

    @Test
    fun verifyCategoriesAndCommands() {
        val scenario = ActivityScenario.launch(Preferences::class.java)
        scenario.onActivity { activity ->
            val fragment = ControlsSettingsFragment()
            activity.supportFragmentManager.commitNow {
                replace(R.id.settings_container, fragment)
            }

            val screen = fragment.preferenceScreen
            assertThat(screen, notNullValue())

            // The "Command mapping" category should be gone.
            val commandMappingCat = fragment.findPreference<PreferenceCategory>(activity.getString(R.string.controls_command_mapping_cat_key))
            assertThat("Old category should be removed", commandMappingCat, nullValue())

            // Check for new categories by title
            val expectedTitles = listOf(
                R.string.controls_category_answer_buttons,
                R.string.controls_category_flags,
                R.string.controls_category_whiteboard,
                R.string.controls_category_current_card_note,
                R.string.controls_category_navigation,
                R.string.controls_category_misc
            ).map { activity.getString(it) }

            var foundCategories = 0
            for (i in 0 until screen.preferenceCount) {
                val pref = screen.getPreference(i)
                if (pref is PreferenceCategory && expectedTitles.contains(pref.title)) {
                    foundCategories++
                    // Verify it has children
                    assertThat("Category ${pref.title} should have children", pref.preferenceCount > 0, equalTo(true))
                }
            }

            assertThat("All new categories should be present", foundCategories, equalTo(expectedTitles.size))

            // Verify all commands are present
            for (command in ViewerCommand.values()) {
                val pref = fragment.findPreference<Preference>(command.preferenceKey)
                assertThat("Preference for ${command.name} should exist", pref, notNullValue())
            }
        }
    }
}
"}

